@app.route("/api/list-playlists", methods=["POST"])
def list_playlists():
    itunes, ipod = get_ipod()
    if not ipod: 
        pythoncom.CoUninitialize()
        return jsonify({"playlists": []})
    
    names = []
    try:
        for pl in ipod.Playlists:
            if pl.Kind == 2 and pl.SpecialKind == 0:
                names.append(pl.Name)
    except:
        pass

    res = jsonify({"playlists": sorted(list(set(names)))})
    pythoncom.CoUninitialize()
    return res

@app.route("/api/browse-folder", methods=["POST"])
def browse_folder():
    if is_busy: return jsonify({"folder": None})
    while not _tk_result.empty():
        try: _tk_result.get_nowait()
        except: break
    _tk_queue.put('browse')
    try:
        path = _tk_result.get(timeout=60)
        if isinstance(path, bool): path = None
        return jsonify({"folder": path})
    except:
        return jsonify({"folder": None})

@app.route("/api/delete-playlist", methods=["POST"])
def delete_playlist():
    global is_busy
    is_busy = True
    pl_name = request.json.get("playlist")
    
    def generate():
        global is_busy
        log = lambda m: f"data: {m}\n\n"
        yield log(f"🗑️ Action on: {pl_name}")
        
        try:
            itunes, ipod = get_ipod()
            playlist = next((p for p in ipod.Playlists if p.Name == pl_name), None)
            
            if not playlist:
                yield log("❌ Error: Playlist not found.")
                yield log("DONE"); return

            # --- RULE 1: RANDOMX (Soft Delete) ---
            if pl_name.startswith("RANDOMX"):
                yield log("🧹 Random mode detected: Deleting playlist container only...")
                playlist.Delete()
                yield log("✅ Playlist removed (Songs preserved in library).")
            
            # --- RULE 2: STANDARD FOLDER (Hard Delete with Pass 2) ---
            else:
                yield log(f"🔥 Folder mode: Preparing full purge of {pl_name}...")
                
                # 1. Catalog tracks (Name + Artist)
                to_delete = set((t.Name.lower().strip(), t.Artist.lower().strip()) for t in playlist.Tracks)
                total = len(to_delete)
                yield log(f"📦 {total} unique tracks identified for deletion.")

                lib = next(p for p in ipod.Playlists if p.Kind == 1)
                deleted = 0
                
                # --- PASS 1: Strict Match (Name + Artist) ---
                yield log("🔍 Pass 1: Strict matching (Name + Artist)...")
                for i in range(lib.Tracks.Count, 0, -1):
                    try:
                        t = lib.Tracks.Item(i)
                        key = (t.Name.lower().strip(), t.Artist.lower().strip())
                        if key in to_delete:
                            t.Delete()
                            deleted += 1
                            to_delete.discard(key)
                    except Exception as e:
                        err = str(e).lower()
                        if "playlist" in err and "deleted" in err:
                            # Refresh COM pointers if they become stale
                            try:
                                itunes, ipod = get_ipod()
                                lib = next(p for p in ipod.Playlists if p.Kind == 1)
                            except: pass
                        continue
                
                yield log(f"📊 Pass 1 finished: {deleted}/{total} removed.")

                # --- PASS 2: Stubborn Files (Name Only) ---
                if to_delete:
                    yield log(f"↻ Pass 2: {len(to_delete)} stubborn file(s) remaining...")
                    for k in to_delete:
                        yield log(f"  → Retrying: '{k[0]}' (Artist: '{k[1]}')")
                    
                    names_only = {k[0] for k in to_delete}
                    try:
                        # Second fresh connection for the safety pass
                        itunes2, ipod2 = get_ipod()
                        lib2 = next(p for p in ipod2.Playlists if p.Kind == 1)
                        for i in range(lib2.Tracks.Count, 0, -1):
                            try:
                                t = lib2.Tracks.Item(i)
                                tname = t.Name.lower().strip()
                                if tname in names_only:
                                    t.Delete()
                                    deleted += 1
                                    names_only.discard(tname)
                            except: continue
                    except: pass
                    yield log(f"📊 Pass 2 finished: {deleted}/{total} total removed.")

                yield log(f"✅ Final result: {deleted}/{total} files purged from device.")
                
                # Finally delete the playlist container
                try:
                    pl_check = next((p for p in ipod.Playlists if p.Name == pl_name), None)
                    if pl_check:
                        pl_check.Delete()
                except: pass

            yield log("💾 Syncing iPod database...")
            itunes.UpdateIPod()
            yield log("DONE")
            
        except Exception as e:
            yield log(f"❌ Critical Error: {str(e)}")
            yield log("DONE")
        finally:
            is_busy = False
            pythoncom.CoUninitialize()
            
    return Response(stream_with_context(generate()), mimetype="text/event-stream")


@app.route("/api/sync", methods=["POST"])
def sync():
    global is_busy
    is_busy = True
    data = request.json
    folder = Path(data.get("folder", ""))
    
    def generate():
        global is_busy
        log = lambda m: f"data: {m}\n\n"
        
        try:
            # --- PHASE 1 : WINDOWS FILE OPERATIONS ONLY ---
            yield log(f"🚀 Phase 1: Windows file system operations")
            
            # On récupère la liste initiale
            mp3_files = sorted(folder.glob("*.mp3"))
            
            # 1. WINDOWS RENOMME TOUS LES MP3 (FILE NAME PHYSIQUE)
            yield log("  📁 Step 1: Renaming all physical files...")
            renamed_files = []
            for mp3 in mp3_files:
                original_stem = mp3.stem
                new_filename = f"{slugify(original_stem)}.mp3"
                new_path = mp3.parent / new_filename
                
                # SI LE NOM CHANGE (même juste la casse)
                if mp3.name != new_filename:
                    # Sécurité : Si on change juste la casse (ex: UIAp -> uiap)
                    # On passe par un nom temporaire pour ne pas perdre le fichier
                    temp_path = mp3.parent / f"TEMP_{random.randint(1000,9999)}_{mp3.name}"
                    
                    try:
                        mp3.rename(temp_path)       # Etape A : Vers temporaire
                        if new_path.exists():        # Etape B : Nettoyage si conflit
                            new_path.unlink()
                        temp_path.rename(new_path)  # Etape C : Vers nom final
                    except Exception as e:
                        yield log(f"⚠️ Erreur rename sur {mp3.name}: {e}")
                        continue
                
                renamed_files.append(new_path)

            # 2. WINDOWS MODIFIE TOUS LES TITRES (TITLE = NEW FILE NAME)
            # Puis modifie Album et Artiste
            yield log("  🏷️ Step 2: Applying New Filename to Title tags...")
            for path in renamed_files:
                # On extrait le nom physique sans extension pour le titre
                new_title = path.stem 
                for _ in range(3): # Sécurité verrous Windows
                    try:
                        clean_tags(path, new_title, folder.name)
                        break
                    except:
                        time.sleep(0.5)
            
            yield log("  ✅ Windows phase completed successfully.")

            # --- SÉCURITÉ : STABILISATION ---
            yield log("⏳ Waiting for disk synchronization...")
            time.sleep(3)

            # --- PHASE 2 : ITUNES AUTHORIZATION ---
            yield log("🚀 Phase 2: iTunes Authorization and Transfer")
            pythoncom.CoInitialize()
            itunes, ipod = get_ipod()
            
            if not ipod:
                yield log("❌ iPod not found."); return

            itunes.UpdateIPod()
            playlist = next((p for p in ipod.Playlists if p.Name == folder.name), None)
            if not playlist: 
                playlist = itunes.CreatePlaylistInSource(folder.name, ipod)
                
            # --- NETTOYAGE DES FICHIERS SUPPRIMÉS SUR WINDOWS ---
            yield log("🧹 Syncing deletions: Checking for removed files...")
            
            # 1. On prépare la liste des noms (slugifiés) présents sur le disque
            files_on_disk = {p.stem.lower().strip() for p in renamed_files}
            
            # 2. On parcourt iTunes pour voir s'il y a des intrus
            itunes_tracks = playlist.Tracks
            deleted_count = 0
            
            # On boucle à l'envers pour ne pas décaler les index iTunes lors de la suppression
            for i in range(itunes_tracks.Count, 0, -1):
                t = itunes_tracks.Item(i)
                t_name = t.Name.lower().strip()
                
                if t_name not in files_on_disk:
                    yield log(f"  🗑️ Removing from iPod (deleted on disk): {t.Name}")
                    t.Delete() # Supprime de la playlist et libère l'espace sur l'iPod
                    deleted_count += 1
            
            if deleted_count > 0:
                yield log(f"  ✅ {deleted_count} tracks purged from iPod.")
            else:
                yield log("  🆗 No deletions needed.")
            
            existing_tracks = {t.Name.lower().strip() for t in playlist.Tracks}
            
            transfers = 0
            updates = 0
            
            # Créer un dictionnaire pour accéder aux morceaux iTunes par leur nom
            # (Plus rapide qu'une boucle dans une boucle)
            itunes_lookup = {t.Name.lower().strip(): t for t in playlist.Tracks}

            for path in renamed_files:
                current_title = path.stem
                clean_title_key = current_title.lower().strip()

                if clean_title_key not in itunes_lookup:
                    yield log(f"  📥 iTunes Import (New): {current_title}")
                    operation = playlist.AddFile(str(path.resolve()))
                    if operation:
                        while operation.InProgress:
                            time.sleep(0.3)
                    
                    # On récupère le morceau ajouté
                    time.sleep(0.5)
                    new_track = playlist.Tracks.Item(playlist.Tracks.Count)
                    
                    # On définit juste le strict nécessaire (iTunes le lira depuis le tag ID3)
                    new_track.Name = current_title
                    new_track.Artist = folder.name
                    new_track.Album = folder.name
                    transfers += 1
                else:
                    # LE FICHIER EST DÉJÀ LÀ
                    # On ne fait plus rien du tout : on laisse le fichier tel quel.
                    # Pas de UpdateTracksFromFile, pas de refresh, pas d'artwork.
                    # C'est beaucoup plus stable et rapide.
                    yield log(f"  ⏭️ Already exists: {current_title} (Skipping refresh)")
                    updates += 1

            if transfers > 0 or updates > 0:
                yield log(f"💾 Syncing {transfers} new and {updates} updated tracks...")
                try: ipod.Update()
                except: pass

            yield log("🔌 Operation Finished. DONE")

        except Exception as e:
            yield log(f"❌ Critical Error: {str(e)}")
        finally:
            is_busy = False
            pythoncom.CoUninitialize()

    return Response(stream_with_context(generate()), mimetype="text/event-stream")

def _generate_random_playlist(count):
    global is_busy
    log = lambda m: f"data: {m}\n\n"

    try:
        pythoncom.CoInitialize()
        itunes, ipod = get_ipod()
        if not ipod:
            yield log("❌ Error: iPod not found.")
            yield log("DONE")
            return

        # Use Item(1) to avoid SpecialKind errors and get the Master Library
        lib = next((p for p in ipod.Playlists if p.Kind == 1), None)
        if not lib:
            yield log("❌ Error: Main library not found.")
            yield log("DONE")
            return

        total = lib.Tracks.Count
        yield log(f"📦 Library: {total} tracks available.")

        if total < count:
            yield log(f"⚠️ Only {total} tracks found - adjusting count.")
            count = total

        # Select random indices
        indices = random.sample(range(1, total + 1), count)
        yield log(f"🎲 {count} tracks selected at random.")

        # Create short name: RANDOMX10_ABCD
        suffix = ''.join(random.choices(string.ascii_uppercase, k=4))
        pl_name = f"RANDOMX{count}_{suffix}"
        
        # Create playlist object
        playlist = itunes.CreatePlaylistInSource(pl_name, ipod)
        yield log(f"📋 Playlist created: {pl_name}")

        added = 0
        for idx in indices:
            try:
                track = lib.Tracks.Item(idx)
                playlist.AddTrack(track)
                added += 1
                if added % 5 == 0:
                    yield log(f"  ➕ {added}/{count} tracks linked...")
            except Exception as e:
                yield log(f"  ⚠️ Skipping track #{idx}: {e}")
                continue

        # NO SMOOTHING HERE: We preserve original tags (Artist/Album/Year)
        
        yield log("💾 Finalizing database sync...")
        itunes.UpdateIPod()
        yield log(f"✅ Done! '{pl_name}' is now on your iPod.")
        yield log("DONE")

    except Exception as e:
        yield log(f"❌ Critical Error: {str(e)}")
        yield log("DONE")
    finally:
        is_busy = False
        pythoncom.CoUninitialize()


