def resource_path(relative_path):
    """ Calcule le chemin absolu vers la ressource, compatible dev et PyInstaller """
    try:
        # PyInstaller crée un dossier temporaire _MEIxxxx
        base_path = sys._MEIPASS
    except Exception:
        base_path = os.path.abspath(".")
    return os.path.join(base_path, relative_path)

@app.route("/")
def index():
    # Utilise resource_path pour localiser index.html
    path = resource_path("index.html")
    return open(path, encoding="utf-8").read()

# --- SERVER RUNNER ---
# --- SERVER RUNNER ---
def run_flask():
    # threaded=True est important pour le streaming SSE
    app.run(port=5000, threaded=True, debug=False, use_reloader=False)

if __name__ == "__main__":
    import ctypes
    # On définit l'ID pour la barre des tâches
    ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID("mamps.ipod.manager")

    # On force l'icône de la fenêtre invisible de Python/Tkinter
    try:
        icon_path = resource_path("myico.ico")
        root = tk.Tk()
        root.iconbitmap(icon_path)
        root.withdraw()
    except:
        pass
    # ------------------------------------------------

    def launch():
        url = "http://127.0.0.1:5000"
        browsers = [
            ("edge", [
                "C:\\Program Files (x86)\\Microsoft\\Edge\\Application\\msedge.exe",
                "C:\\Program Files\\Microsoft\\Edge\\Application\\msedge.exe",
            ]),
            ("firefox", [
                "C:\\Program Files\\Mozilla Firefox\\firefox.exe",
                "C:\\Program Files (x86)\\Mozilla Firefox\\firefox.exe",
            ]),
            ("chrome", [
                "C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe",
                "C:\\Program Files (x86)\\Google\\Chrome\\Application\\chrome.exe",
                os.path.expanduser("~\\AppData\\Local\\Google\\Chrome\\Application\\chrome.exe"),
            ]),
        ]
        for browser_name, paths in browsers:
            for path in paths:
                if os.path.exists(path):
                    if browser_name == "firefox":
                        subprocess.Popen([path, "--new-window", url])
                    else:
                        # Le mode --app= utilise normalement l'icône du processus parent
                        subprocess.Popen([path, f"--app={url}", "--window-size=1100,700"])
                    return
        webbrowser.open(url)

    def watchdog():
        time.sleep(5) 
        while True:
            time.sleep(3)
            if time.time() - _last_heartbeat > 30: 
                os._exit(0)

    # Lancement des processus
    threading.Timer(2.5, launch).start()
    threading.Thread(target=watchdog, daemon=True).start()
    app.run(port=5000, debug=False, threaded=True)
